// AllReviews is the resolver for the allReviews field.
func (r *queryResolver) AllReviews(ctx context.Context, limit *int, offset *int, rating *int, reviewType *string) (*model.ReviewConnection, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	l := int32(50)
	if limit != nil {
		l = int32(*limit)
	}
	o := int32(0)
	if offset != nil {
		o = int32(*offset)
	}

	var ratingParam pgtype.Int4
	if rating != nil {
		ratingParam = pgtype.Int4{Int32: int32(*rating), Valid: true}
	}
	var reviewTypeParam pgtype.Text
	if reviewType != nil && *reviewType != "" {
		reviewTypeParam = pgtype.Text{String: *reviewType, Valid: true}
	}

	dbReviews, err := r.Queries.ListAllReviewsFiltered(ctx, db.ListAllReviewsFilteredParams{
		Limit:      l,
		Offset:     o,
		Rating:     ratingParam,
		ReviewType: reviewTypeParam,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to list reviews: %w", err)
	}

	count, err := r.Queries.CountAllReviewsFiltered(ctx, db.CountAllReviewsFilteredParams{
		Rating:     ratingParam,
		ReviewType: reviewTypeParam,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to count reviews: %w", err)
	}

	reviews := make([]*model.Review, len(dbReviews))
	for i, rv := range dbReviews {
		review := dbReviewToGQL(rv)

		// Populate the associated booking.
		if booking, err := r.Queries.GetBookingByID(ctx, rv.BookingID); err == nil {
			review.Booking = dbBookingToGQL(booking)
		}

		// Populate the reviewer user.
		if rv.ReviewerUserID.Valid {
			if user, err := r.Queries.GetUserByID(ctx, rv.ReviewerUserID); err == nil {
				review.Reviewer = dbUserToGQL(user)
			}
		}

		reviews[i] = review
	}

	return &model.ReviewConnection{
		Reviews:    reviews,
		TotalCount: int(count),
	}, nil
}
